-- ==================================================
-- SCRIPT MAESTRO DE REPARACION CXC
-- ==================================================

-- 1. ELIMINAR DUPLICADOS EXACTOS SIN CONTEO
DELETE a1 FROM asientos a1
INNER JOIN asientos a2 ON a1.id > a2.id 
  AND a1.empresa_id = a2.empresa_id
  AND a1.cuenta_id = a2.cuenta_id
  AND (ABS(a1.debito - a2.debito) < 0.01)
  AND (ABS(a1.credito - a2.credito) < 0.01)
  AND a1.descripcion = a2.descripcion
  AND a1.conteo IS NULL
  AND a2.conteo IS NULL
WHERE a1.empresa_id = 1
  AND a1.cuenta_id = (SELECT id FROM puc_cuentas WHERE codigo='11050101' AND empresa_id=1 LIMIT 1);

